import { getOrderlyEnvConfig } from "@/utils/environment";
import { apiClient } from "@/utils/api";

const CAMPAIGN_CACHE_TTL_MS = 24 * 60 * 60 * 1000;
const CAMPAIGN_CACHE_KEY_PREFIX = "orderly-one:active-campaigns";

let inFlightCampaignCheck: Promise<boolean> | null = null;

type CampaignCacheEntry = {
  expiresAt?: number;
  hasActiveCampaigns?: boolean;
};

function collectRows(value: unknown): Record<string, unknown>[] {
  if (!value) return [];
  if (Array.isArray(value)) return value.flatMap(entry => collectRows(entry));
  if (typeof value !== "object") return [];

  const objectValue = value as Record<string, unknown>;
  if (
    "id" in objectValue ||
    "name" in objectValue ||
    "start_time" in objectValue ||
    "startTime" in objectValue
  )
    return [objectValue];
  return collectRows(objectValue.data ?? objectValue.rows);
}

function timestampValue(value: unknown) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric) || numeric <= 0) return undefined;
  return numeric < 10_000_000_000 ? numeric * 1000 : numeric;
}

function isActiveCampaign(row: Record<string, unknown>) {
  const now = Date.now();
  const startTime = timestampValue(row.start_time ?? row.startTime);
  const endTime = timestampValue(row.end_time ?? row.endTime);
  return Boolean(startTime && endTime && startTime <= now && endTime >= now);
}

export function getCampaignCacheKey(apiBaseUrl: string) {
  return `${CAMPAIGN_CACHE_KEY_PREFIX}:${apiBaseUrl}`;
}

export function readCachedCampaignCheck(cacheKey: string) {
  if (typeof window === "undefined") return undefined;
  const raw = window.localStorage.getItem(cacheKey);
  if (!raw) return undefined;

  try {
    const cached = JSON.parse(raw) as CampaignCacheEntry;
    if (!cached.expiresAt || cached.expiresAt <= Date.now()) {
      window.localStorage.removeItem(cacheKey);
      return undefined;
    }
    return Boolean(cached.hasActiveCampaigns);
  } catch {
    window.localStorage.removeItem(cacheKey);
    return undefined;
  }
}

function writeCachedCampaignCheck(
  cacheKey: string,
  hasActiveCampaigns: boolean
) {
  if (typeof window === "undefined") return;
  const cached: CampaignCacheEntry = {
    expiresAt: Date.now() + CAMPAIGN_CACHE_TTL_MS,
    hasActiveCampaigns,
  };
  window.localStorage.setItem(cacheKey, JSON.stringify(cached));
}

export async function hasActivePublicCampaigns() {
  const apiBaseUrl = getOrderlyEnvConfig().apiBaseUrl;
  const cacheKey = getCampaignCacheKey(apiBaseUrl);
  const cachedResult = readCachedCampaignCheck(cacheKey);
  if (cachedResult !== undefined) return cachedResult;

  if (inFlightCampaignCheck) return inFlightCampaignCheck;

  inFlightCampaignCheck = (async () => {
    let payload: {
      success?: boolean;
      data?: unknown;
      rows?: unknown;
    };
    try {
      payload = await apiClient({
        endpoint: "/v1/public/campaigns?only_show_alive=true",
        token: null,
        showToastOnError: false,
      });
    } catch {
      return false;
    }

    const hasActiveCampaigns =
      payload.success !== false && collectRows(payload).some(isActiveCampaign);
    writeCachedCampaignCheck(cacheKey, hasActiveCampaigns);
    return hasActiveCampaigns;
  })().finally(() => {
    inFlightCampaignCheck = null;
  });

  return inFlightCampaignCheck;
}
