import React, { useEffect, useState } from "react";
import { useLocation } from "@remix-run/react";
import { LocalizedLink, useLocalizedNavigate } from "@/utils/localizedRoute";
import { Menu, X } from "lucide-react";
import { useAccount, useConnections, useDisconnect } from "wagmi";
import { OdsButton } from "./OdsButton";
import {
  OrderlyOneLogoLockup,
  OrderlyOneMobileLogoLockup,
} from "./OrderlyOneLogoLockup";
import { useTranslation } from "@/i18n";
import { LanguageSwitcher } from "./LanguageSwitcher";
import { disconnectWalletCompletely } from "@/utils/session";
import { getOrderlyEnv, getOrderlyEnvConfig } from "@/utils/environment";
import { signedAdminRequest } from "@/utils/adminKeyAuth";
import {
  hasActivePublicCampaigns,
  getCampaignCacheKey,
  readCachedCampaignCheck,
} from "@/utils/campaigns";
import { getOrderlyAppLinks } from "@/utils/orderlyAppLinks";
import { OdsArrowOutwardIcon } from "./OdsIcons";
import { type Profile, getProfile } from "@/utils/branding-shared";
import { walletGetItem, walletSetItem } from "@/utils/storage";

function getDistributorNameFromSummary(payload: unknown): string | undefined {
  const root =
    payload && typeof payload === "object" && !Array.isArray(payload)
      ? (payload as Record<string, unknown>)
      : {};
  const data =
    root.data && typeof root.data === "object" && !Array.isArray(root.data)
      ? (root.data as Record<string, unknown>)
      : root;
  const value =
    data.distributor_name ||
    data.distributorName ||
    root.distributor_name ||
    root.distributorName;
  return typeof value === "string" && value.trim() ? value.trim() : undefined;
}

function scrollToTopAfterNavigation() {
  window.requestAnimationFrame(() => {
    window.requestAnimationFrame(() =>
      window.scrollTo({ top: 0, left: 0, behavior: "auto" })
    );
  });
}

function getLoginContext() {
  if (typeof window === "undefined") return null;
  const raw = walletGetItem("orderlyLoginContext");
  if (!raw) return null;
  try {
    return JSON.parse(raw) as {
      method?: string;
      walletAddress?: string;
      accountId?: string;
    };
  } catch {
    return null;
  }
}

function getRoutePathname(pathname: string) {
  const segments = pathname.split("/").filter(Boolean);
  if (segments.length > 0 && /^[a-z]{2}$/i.test(segments[0])) {
    return segments.length === 1 ? "/" : `/${segments.slice(1).join("/")}`;
  }
  return pathname;
}

export function PublicHeader() {
  const navigate = useLocalizedNavigate();
  const location = useLocation();
  const { t } = useTranslation();
  const { address } = useAccount();
  const connections = useConnections();
  const { disconnectAsync } = useDisconnect();
  const [profile, setProfile] = useState<Profile | null>(null);
  const [context, setContext] =
    useState<ReturnType<typeof getLoginContext>>(null);
  const [menuOpen, setMenuOpen] = useState(false);
  const [navMenuOpen, setNavMenuOpen] = useState(false);
  const [showCampaigns, setShowCampaigns] = useState(() => {
    try {
      const cached = readCachedCampaignCheck(
        getCampaignCacheKey(getOrderlyEnvConfig().apiBaseUrl)
      );
      return cached ?? false;
    } catch {
      return false;
    }
  });
  const [navReady, setNavReady] = useState(() => {
    try {
      const cached = readCachedCampaignCheck(
        getCampaignCacheKey(getOrderlyEnvConfig().apiBaseUrl)
      );
      return cached !== undefined;
    } catch {
      return false;
    }
  });
  const isAmbassadorDistributor =
    profile?.role === "ambassador" || profile?.brokerId === "ambassador";

  useEffect(() => {
    setProfile(getProfile());
    setContext(getLoginContext());
  }, []);

  useEffect(() => {
    let cancelled = false;
    hasActivePublicCampaigns()
      .then(hasCampaigns => {
        if (!cancelled) {
          setShowCampaigns(hasCampaigns);
          setNavReady(true);
        }
      })
      .catch(() => {
        if (!cancelled) {
          setShowCampaigns(false);
          setNavReady(true);
        }
      });

    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    function refreshSession() {
      setProfile(getProfile());
      setContext(getLoginContext());
    }

    window.addEventListener("authChanged", refreshSession);
    window.addEventListener("storage", refreshSession);
    return () => {
      window.removeEventListener("authChanged", refreshSession);
      window.removeEventListener("storage", refreshSession);
    };
  }, []);

  useEffect(() => {
    if (!isAmbassadorDistributor) return;

    let cancelled = false;
    signedAdminRequest({ endpoint: "/v1/vanguard/summary", method: "GET" })
      .then(summary => {
        if (cancelled) return;
        const distributorName = getDistributorNameFromSummary(summary);
        if (!distributorName) return;
        setProfile(current => {
          const next = {
            ...(current || getProfile() || {}),
            builderName: distributorName,
            brokerId: "ambassador",
            role: "ambassador",
          };
          walletSetItem("orderlyProfile", JSON.stringify(next));
          return next;
        });
        window.dispatchEvent(new CustomEvent("profileUpdated"));
      })
      .catch(() => {
        // Keep the locally cached distributor name if Vanguard summary is unavailable.
      });

    return () => {
      cancelled = true;
    };
  }, [isAmbassadorDistributor]);

  const walletText = address
    ? `${address.slice(0, 6)}...${address.slice(-4)}`
    : context?.method === "wallet" && context.walletAddress
      ? `${context.walletAddress.slice(0, 6)}...${context.walletAddress.slice(-4)}`
      : context?.method === "api" && context.accountId
        ? `${context.accountId.slice(0, 6)}...${context.accountId.slice(-4)}`
        : "";
  const isWalletConnected =
    !!address || (!!context?.walletAddress && context?.method === "wallet");
  const hasFullSession = !!profile || !!context;
  const isLoggedIn = hasFullSession || isWalletConnected;
  const displayName = profile?.builderName || walletText || t("common.user");
  const orderlyAppLinks = getOrderlyAppLinks(getOrderlyEnv());
  const dashboardPath = isAmbassadorDistributor
    ? "/distributor-dashboard"
    : "/home";
  const isLoginPage =
    location.pathname.split("/").filter(Boolean).pop() === "login";
  const routePathname = getRoutePathname(location.pathname);
  const navLinkClass = (active = false) =>
    `whitespace-nowrap text-base font-medium leading-[120%] transition-colors hover:text-[var(--fg-base)] ${
      active ? "text-[var(--fg-base)]" : "text-[var(--fg-secondary)]"
    }`;
  const externalNavLinkClass =
    "inline-flex items-center gap-1 whitespace-nowrap text-base font-medium leading-[120%] text-[var(--fg-secondary)] transition-colors hover:text-[var(--fg-base)]";

  function handleTopNavClick(
    event: React.MouseEvent<HTMLAnchorElement>,
    path: string
  ) {
    event.preventDefault();
    setNavMenuOpen(false);
    if (routePathname === path) return;
    navigate(path);
    scrollToTopAfterNavigation();
  }

  async function handleLogout() {
    await disconnectWalletCompletely(disconnectAsync, connections);
    setProfile(null);
    setContext(null);
    setMenuOpen(false);
  }

  return (
    <>
      <header className="sticky top-0 z-50 border-b border-[var(--border-subtle)] bg-[var(--bg-base)]/80 backdrop-blur-[12px]">
        <div className="mx-auto flex h-14 max-w-[1440px] items-center justify-between px-6 md:h-[100px] xl:px-20">
          <div className="flex min-w-0 flex-1 items-center gap-4">
            <LocalizedLink
              to="/"
              onClick={event => handleTopNavClick(event, "/")}
              className="flex h-8 items-center"
              aria-label="Orderly One home"
            >
              <OrderlyOneMobileLogoLockup className="h-[26px] w-[149px] shrink-0 md:hidden" />
              <OrderlyOneLogoLockup className="hidden h-8 w-[238.143px] shrink-0 md:block" />
            </LocalizedLink>
            <nav
              className={`hidden min-w-0 flex-1 items-center justify-end gap-6 px-6 xl:flex transition-opacity duration-300 ${navReady ? "opacity-100" : "opacity-0"}`}
            >
              <LocalizedLink
                to="/board"
                onClick={event => handleTopNavClick(event, "/board")}
                className={navLinkClass(
                  routePathname === "/board" ||
                    routePathname.startsWith("/board/")
                )}
              >
                {t("navigation.leaderboard")}
              </LocalizedLink>
              <LocalizedLink
                to="/markets"
                onClick={event => handleTopNavClick(event, "/markets")}
                className={navLinkClass(routePathname === "/markets")}
              >
                {t("common.markets")}
              </LocalizedLink>
              <LocalizedLink
                to="/distributor"
                onClick={event => handleTopNavClick(event, "/distributor")}
                className={navLinkClass(routePathname === "/distributor")}
              >
                {t("navigation.distributorProgram")}
              </LocalizedLink>
              <a
                href={orderlyAppLinks.staking}
                target="_blank"
                rel="noopener noreferrer"
                className={externalNavLinkClass}
              >
                {t("navigation.staking")}
                <OdsArrowOutwardIcon className="h-3 w-3 shrink-0" />
              </a>
              <a
                href={orderlyAppLinks.vaults}
                target="_blank"
                rel="noopener noreferrer"
                className={externalNavLinkClass}
              >
                {t("navigation.strategyVaults")}
                <OdsArrowOutwardIcon className="h-3 w-3 shrink-0" />
              </a>
              {showCampaigns && (
                <a
                  href={orderlyAppLinks.campaigns}
                  target="_blank"
                  rel="noopener noreferrer"
                  className={externalNavLinkClass}
                >
                  {t("navigation.campaigns")}
                  <OdsArrowOutwardIcon className="h-3 w-3 shrink-0" />
                </a>
              )}
            </nav>
          </div>

          <div className="relative flex shrink-0 items-center gap-2 md:gap-4">
            <button
              type="button"
              aria-label="Open navigation menu"
              aria-expanded={navMenuOpen}
              onClick={() => {
                setNavMenuOpen(open => !open);
                setMenuOpen(false);
              }}
              className="inline-flex h-8 w-[56px] items-center justify-center rounded-[24px] bg-[var(--bg-secondary)] text-[var(--fg-base)] transition-opacity hover:opacity-90 md:h-10 md:w-[68px] xl:hidden"
            >
              {navMenuOpen ? (
                <X className="h-5 w-5 md:h-6 md:w-6" />
              ) : (
                <Menu className="h-5 w-5 md:h-6 md:w-6" />
              )}
            </button>
            <LanguageSwitcher />
            {isLoggedIn ? (
              <div className="relative">
                <OdsButton
                  variant="primary"
                  size="small"
                  className="md:h-10 md:px-5 md:text-[16px]"
                  onClick={() => setMenuOpen(v => !v)}
                  aria-expanded={menuOpen}
                  aria-haspopup="menu"
                  title={displayName}
                >
                  {walletText || displayName}
                </OdsButton>
                {menuOpen && (
                  <div className="absolute right-0 top-[calc(100%+8px)] z-50 flex min-w-[240px] flex-col gap-1.5 rounded-lg bg-[var(--bg-surface-primary)] p-4 shadow-popout">
                    {hasFullSession && (
                      <>
                        <LocalizedLink
                          to={dashboardPath}
                          className="flex min-h-[51px] items-center rounded-lg px-3 py-2 text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-[var(--bg-hover)]"
                          onClick={() => setMenuOpen(false)}
                        >
                          {isAmbassadorDistributor
                            ? t("navigation.dashboard")
                            : t("navigation.myDex")}
                        </LocalizedLink>
                        {isAmbassadorDistributor && (
                          <LocalizedLink
                            to="/settings"
                            className="flex min-h-[51px] items-center rounded-lg px-3 py-2 text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-[var(--bg-hover)]"
                            onClick={() => setMenuOpen(false)}
                          >
                            {t("navigation.settings")}
                          </LocalizedLink>
                        )}
                      </>
                    )}
                    <button
                      type="button"
                      onClick={handleLogout}
                      className="flex min-h-[51px] items-center rounded-lg px-3 py-2 text-left text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-[var(--bg-hover)]"
                    >
                      {hasFullSession
                        ? t("common.logOut")
                        : t("login.disconnect")}
                    </button>
                  </div>
                )}
              </div>
            ) : !isLoginPage ? (
              <OdsButton
                variant="primary"
                size="small"
                className="md:h-10 md:px-5 md:text-[16px]"
                onClick={() => navigate("/login")}
              >
                {t("common.connect")}
              </OdsButton>
            ) : null}
            {navMenuOpen && (
              <nav className="absolute left-0 top-[calc(100%+8px)] z-50 w-[240px] xl:hidden">
                <div className="flex flex-col gap-1.5 rounded-lg bg-[var(--bg-surface-primary)] p-4 shadow-popout">
                  <LocalizedLink
                    to="/board"
                    onClick={event => handleTopNavClick(event, "/board")}
                    className="flex min-h-[51px] items-center rounded-lg px-3 py-2 text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-[var(--bg-hover)]"
                  >
                    {t("navigation.leaderboard")}
                  </LocalizedLink>
                  {isAmbassadorDistributor && (
                    <>
                      <LocalizedLink
                        to="/distributor-dashboard"
                        onClick={() => setNavMenuOpen(false)}
                        className="flex min-h-[51px] items-center rounded-lg px-3 py-2 text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-[var(--bg-hover)]"
                      >
                        {t("navigation.dashboard")}
                      </LocalizedLink>
                      <LocalizedLink
                        to="/settings"
                        onClick={() => setNavMenuOpen(false)}
                        className="flex min-h-[51px] items-center rounded-lg px-3 py-2 text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-[var(--bg-hover)]"
                      >
                        {t("navigation.settings")}
                      </LocalizedLink>
                    </>
                  )}
                  <LocalizedLink
                    to="/markets"
                    onClick={event => handleTopNavClick(event, "/markets")}
                    className="flex min-h-[51px] items-center rounded-lg px-3 py-2 text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-[var(--bg-hover)]"
                  >
                    {t("common.markets")}
                  </LocalizedLink>
                  <LocalizedLink
                    to="/distributor"
                    onClick={event => handleTopNavClick(event, "/distributor")}
                    className="flex min-h-[51px] items-center rounded-lg px-3 py-2 text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-[var(--bg-hover)]"
                  >
                    {t("navigation.distributorProgram")}
                  </LocalizedLink>
                  <a
                    href={orderlyAppLinks.staking}
                    target="_blank"
                    rel="noopener noreferrer"
                    onClick={() => setNavMenuOpen(false)}
                    className="flex min-h-[51px] items-center justify-between rounded-lg px-3 py-2 text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-[var(--bg-hover)]"
                  >
                    <span>{t("navigation.staking")}</span>
                    <OdsArrowOutwardIcon className="h-3 w-3 text-[var(--fg-secondary)]" />
                  </a>
                  <a
                    href={orderlyAppLinks.vaults}
                    target="_blank"
                    rel="noopener noreferrer"
                    onClick={() => setNavMenuOpen(false)}
                    className="flex min-h-[51px] items-center justify-between rounded-lg px-3 py-2 text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-[var(--bg-hover)]"
                  >
                    <span>{t("navigation.strategyVaults")}</span>
                    <OdsArrowOutwardIcon className="h-3 w-3 text-[var(--fg-secondary)]" />
                  </a>
                  {navReady && showCampaigns && (
                    <a
                      href={orderlyAppLinks.campaigns}
                      target="_blank"
                      rel="noopener noreferrer"
                      onClick={() => setNavMenuOpen(false)}
                      className="flex min-h-[51px] items-center justify-between rounded-lg px-3 py-2 text-sm font-medium text-[var(--fg-base)] transition-colors hover:bg-[var(--bg-hover)]"
                    >
                      <span>{t("navigation.campaigns")}</span>
                      <OdsArrowOutwardIcon className="h-3 w-3 text-[var(--fg-secondary)]" />
                    </a>
                  )}
                </div>
              </nav>
            )}
          </div>
        </div>
      </header>
    </>
  );
}
